/* ============================================================================
 * DSL Writer Module Adapter
 *
 * The equalizer between Buhera's two user types, exposed as a dispatchable
 * module. An uninformed user's natural-language instructions become a valid
 * DSL script (generated by the FKAC federation, validated by the DSL's real
 * compiler, repaired on failure) and are then dispatched to the owning module
 * — reaching the SAME executor an informed user's hand-written script does.
 *
 * Client-side adapter: it POSTs to /api/dsl-generate, which hosts the
 * server-only pieces (fs-backed knowledge packs, the LLM cascade). The browser
 * only sees JSON.
 *
 * Instruction shapes:
 *   • { dslId, instructions, execute?, maxRepairs? }
 *   • a plain string — treated as instructions for the default DSL ("vahera")
 * ========================================================================== */

const API_ROUTE = "/api/dsl-generate";
const DEFAULT_DSL = "vahera";

function normaliseInstruction(instruction) {
  if (instruction == null || instruction === "") {
    return { dslId: DEFAULT_DSL, instructions: "", execute: true };
  }
  if (typeof instruction === "string") {
    return { dslId: DEFAULT_DSL, instructions: instruction, execute: true };
  }
  if (typeof instruction === "object") {
    return {
      dslId: String(instruction.dslId || DEFAULT_DSL),
      instructions: String(instruction.instructions || ""),
      // Default to executing: the whole point is to reach the executor. A
      // caller can pass execute:false to only generate + validate.
      execute: instruction.execute !== false,
      maxRepairs: Number.isInteger(instruction.maxRepairs) ? instruction.maxRepairs : undefined,
    };
  }
  return { dslId: DEFAULT_DSL, instructions: String(instruction), execute: true };
}

export const dslWriterModule = {
  id: "dsl-writer",

  describe() {
    return {
      id: "dsl-writer",
      description:
        "DSL Writer: compiles natural-language instructions into a valid DSL " +
        "script (federation-generated, validated by the DSL's real compiler, " +
        "repaired on failure) and dispatches it to the owning module. Lets an " +
        "uninformed user reach the same executor an informed user's script does.",
      instructions: [
        'dispatch("dsl-writer", "store a memory \\"x\\"=\\"1\\" then find nearest to x")',
        'dispatch("dsl-writer", { dslId: "vahera", instructions: "...", execute: true })',
        'dispatch("dsl-writer", { dslId: "vahera", instructions: "...", execute: false })  // generate + validate only',
      ],
    };
  },

  async execute(instruction, _actBudget = 1) {
    const { dslId, instructions, execute, maxRepairs } = normaliseInstruction(instruction);

    if (!instructions.trim()) {
      return {
        ok: false,
        output_delta: { kind: "text", lines: ["dsl-writer: no instructions provided."] },
        residue: 0,
        completed: true,
      };
    }

    let res;
    try {
      res = await fetch(API_ROUTE, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ dslId, instructions, execute, maxRepairs }),
      });
    } catch (err) {
      return {
        ok: false,
        output_delta: {
          kind: "text",
          lines: [`dsl-writer: network error contacting ${API_ROUTE}.`, err.message || String(err)],
        },
        residue: 0,
        completed: true,
        error: err.message || String(err),
      };
    }

    let body;
    try {
      body = await res.json();
    } catch {
      return {
        ok: false,
        output_delta: { kind: "text", lines: [`dsl-writer: non-JSON response (HTTP ${res.status})`] },
        residue: 0,
        completed: true,
        error: `non-JSON response (HTTP ${res.status})`,
      };
    }

    if (!body.ok) {
      const lines = [`dsl-writer: generation failed (${dslId}).`];
      for (const e of body.errors || []) {
        lines.push(e.line != null ? `  line ${e.line}: ${e.message}` : `  ${e.message}`);
      }
      if ((body.errors || []).some((e) => e.stage === "provider")) {
        lines.push("set OLLAMA_URL, GEMINI_API_KEY, or OPENAI_API_KEY in .env.local");
      }
      if (body.code) lines.push("last attempt:", body.code);
      return {
        ok: false,
        output_delta: { kind: "text", lines },
        residue: 0,
        completed: true,
        error: (body.errors && body.errors[0] && body.errors[0].message) || `HTTP ${res.status}`,
      };
    }

    // Success. Surface the generated code, the federation confidence, and the
    // module's ActResult (when execute was requested).
    const confidence =
      body.federation && typeof body.federation.confidence === "number"
        ? body.federation.confidence
        : null;

    return {
      ok: true,
      output_delta: {
        kind: "dsl_generated",
        dslId,
        code: body.code,
        federation: body.federation,
        repairs: body.repairs,
        act: body.act ?? null,
      },
      // Residue mirrors the aggregate floor (lower = more confident), matching
      // the purpose module's convention of residue = floor.
      residue:
        body.federation && typeof body.federation.aggregate_floor === "number"
          ? body.federation.aggregate_floor
          : confidence != null
          ? Math.round((1 - confidence) * 100)
          : 0,
      completed: true,
    };
  },

  outputCell(_instruction) {
    return { kind: "dsl_generated_cell" };
  },
};
